import{_ as a,c as t,a1 as h,o as i}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Bảng Rainbow","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/5-system-hacking/3-Rainbow-tables.md","filePath":"vi/categories/ethical-hacking-labs/5-system-hacking/3-Rainbow-tables.md"}'),e={name:"vi/categories/ethical-hacking-labs/5-system-hacking/3-Rainbow-tables.md"};function s(c,n,r,o,l,p){return i(),t("div",null,n[0]||(n[0]=[h(`<h1 id="bang-rainbow" tabindex="-1">Bảng Rainbow <a class="header-anchor" href="#bang-rainbow" aria-label="Permalink to &quot;Bảng Rainbow&quot;">​</a></h1><p>RainbowCrack là một chương trình máy tính tạo bảng rainbow để sử dụng trong việc giải mã mật khẩu.</p><p>RainbowCrack <a href="https://project-rainbowcrack.com/documentation.htm" target="_blank" rel="noreferrer">Tài liệu</a></p><h3 id="tong-quan-ve-bang-rainbow" tabindex="-1">Tổng quan về Bảng Rainbow <a class="header-anchor" href="#tong-quan-ve-bang-rainbow" aria-label="Permalink to &quot;Tổng quan về Bảng Rainbow&quot;">​</a></h3><p>Bảng rainbow là một bảng được tính toán trước để đảo ngược hàm băm mật mã, thường được sử dụng để giải mã hash mật khẩu. Bảng thường được sử dụng để khôi phục mật khẩu văn bản thuần bao gồm một tập hợp ký tự giới hạn, đến một độ dài nhất định.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Giới thiệu ngắn gọn về bảng rainbow và sử dụng chúng để giải mã hash và thu được mật khẩu văn bản thuần.</li></ul><h2 id="tao-bang-rainbow" tabindex="-1">Tạo Bảng Rainbow <a class="header-anchor" href="#tao-bang-rainbow" aria-label="Permalink to &quot;Tạo Bảng Rainbow&quot;">​</a></h2><p>Để có bảng rainbow, bạn có thể <a href="https://freerainbowtables.com/" target="_blank" rel="noreferrer">tải xuống</a> hoặc tự tạo bằng cách sử dụng <code>rtgen</code> đi kèm với gói <code>rainbowcrack</code>.</p><p>Cài đặt phiên bản CLI của RainbowCrack:</p><p><code>sudo apt-get install rainbowcrack</code></p><p><strong>Phiên bản GUI</strong>: <a href="https://project-rainbowcrack.com/" target="_blank" rel="noreferrer">https://project-rainbowcrack.com/</a></p><p><strong>Ví dụ sử dụng</strong>: <code>rtgen hash_algorithm charset plaintext_len_min plaintext_len_max table_index chain_len chain_num part_index</code></p><p>Hash Algorithm | Mô tả --- | --- | --- <strong>hash_algorithm</strong> | Bảng rainbow đặc thù cho từng thuật toán băm. Bảng rainbow cho một thuật toán băm cụ thể chỉ giúp giải mã các hash thuộc loại đó. Chương trình rtgen hỗ trợ nhiều thuật toán băm như lm, ntlm, md5, sha1, mysqlsha1, halflmchall, ntlmchall, oracle-SYSTEM và md5-half. Trong ví dụ trên, chúng ta tạo bảng rainbow md5 để tăng tốc giải mã hash md5. <strong>charset</strong> | Bảng ký tự bao gồm tất cả các ký tự có thể cho văn bản thuần. &quot;loweralpha-numeric&quot; đại diện cho &quot;abcdefghijklmnopqrstuvwxyz0123456789&quot;, được định nghĩa trong file cấu hình charset.txt. <strong>plaintext_len_min plaintext_len_max</strong> | Hai tham số này giới hạn phạm vi độ dài văn bản thuần của bảng rainbow. Trong ví dụ trên, phạm vi độ dài văn bản thuần là 1 đến 7. Vì vậy các văn bản thuần như &quot;a&quot; và &quot;abcdefg&quot; có thể được chứa trong bảng rainbow được tạo. Nhưng văn bản thuần &quot;abcdefgh&quot; với độ dài 8 sẽ không được chứa. <strong>table_index1</strong> | Tham số table_index chọn hàm giảm. Bảng rainbow với tham số table_index khác nhau sử dụng hàm giảm khác nhau. <strong>chain_len1</strong> | Đây là độ dài chuỗi rainbow. Chuỗi rainbow dài hơn lưu trữ nhiều văn bản thuần hơn và cần thời gian tạo lâu hơn. <strong>chain_num1</strong> | Số lượng chuỗi rainbow cần tạo. Bảng rainbow đơn giản là một mảng các chuỗi rainbow. Kích thước mỗi chuỗi rainbow là 16 byte. <strong>part_index</strong> | Để lưu trữ một bảng rainbow lớn trong nhiều file nhỏ hơn, sử dụng số khác nhau trong tham số này cho mỗi phần và giữ tất cả các tham số khác giống nhau.</p><p><strong>Ví dụ:</strong></p><p><code>rtgen md5 loweralpha-numeric 1 7 0 3800 33554432 0</code></p><p>CPU sẽ bận tính toán các chuỗi rainbow. Trên hệ thống có bộ xử lý đa lõi, tất cả các lõi được sử dụng đầy đủ.</p><p>Để tạm dừng tạo bảng, chỉ cần nhấn Ctrl+C và chương trình rtgen sẽ thoát. Lần sau nếu chương trình rtgen được chạy với chính xác các tham số tương tự, việc tạo bảng sẽ được tiếp tục.</p><p><strong>Lệnh này mất hàng giờ để hoàn thành với bộ xử lý thông thường.</strong></p><p>Sau khi tạo bảng rainbow, bạn cần sắp xếp nó. Rainbowcrack đi kèm với chương trình <code>rtsort</code>, sắp xếp các chuỗi rainbow theo điểm cuối để cho phép tìm kiếm nhị phân giúp bộ xử lý truy cập nhanh hơn.</p><p><code>rtsort *.rt</code></p><h2 id="giai-ma" tabindex="-1">Giải mã <a class="header-anchor" href="#giai-ma" aria-label="Permalink to &quot;Giải mã&quot;">​</a></h2><p>Để hiển thị cách sử dụng và tùy chọn, chỉ cần nhập <code>rcrack</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>usage: ./rcrack path [path] [...] -h hash</span></span>
<span class="line"><span>       ./rcrack path [path] [...] -l hash_list_file</span></span>
<span class="line"><span>       ./rcrack path [path] [...] -lm pwdump_file</span></span>
<span class="line"><span>       ./rcrack path [path] [...] -ntlm pwdump_file</span></span>
<span class="line"><span>path:              directory where rainbow tables (*.rt, *.rtc) are stored</span></span>
<span class="line"><span>-h hash:           load single hash</span></span>
<span class="line"><span>-l hash_list_file: load hashes from a file, each hash in a line</span></span>
<span class="line"><span>-lm pwdump_file:   load lm hashes from pwdump file</span></span>
<span class="line"><span>-ntlm pwdump_file: load ntlm hashes from pwdump file</span></span>
<span class="line"><span></span></span>
<span class="line"><span>implemented hash algorithms:</span></span>
<span class="line"><span>    lm HashLen=8 PlaintextLen=0-7</span></span>
<span class="line"><span>    ntlm HashLen=16 PlaintextLen=0-15</span></span>
<span class="line"><span>    md5 HashLen=16 PlaintextLen=0-15</span></span>
<span class="line"><span>    sha1 HashLen=20 PlaintextLen=0-20</span></span>
<span class="line"><span>    sha256 HashLen=32 PlaintextLen=0-20</span></span>
<span class="line"><span></span></span>
<span class="line"><span>examples:</span></span>
<span class="line"><span>    ./rcrack . -h 5d41402abc4b2a76b9719d911017c592</span></span>
<span class="line"><span>    ./rcrack . -l hash.txt</span></span></code></pre></div><h1 id="l0phtcrack" tabindex="-1">L0phtCrack <a class="header-anchor" href="#l0phtcrack" aria-label="Permalink to &quot;L0phtCrack&quot;">​</a></h1><p>L0phtCrack là một công cụ kiểm toán mật khẩu chứa các tính năng như lập lịch, trích xuất hash từ phiên bản Windows 64-bit, thuật toán đa xử lý, và giám sát mạng cùng giải mã. Nó có thể nhập và giải mã file mật khẩu UNIX từ máy Windows từ xa.</p><p>Dùng thử miễn phí: <a href="https://www.l0phtcrack.com/" target="_blank" rel="noreferrer">https://www.l0phtcrack.com/</a> Tài liệu: <a href="https://www.l0phtcrack.com/doc/" target="_blank" rel="noreferrer">https://www.l0phtcrack.com/doc/</a></p><h3 id="lien-ket-huu-ich" tabindex="-1">Liên kết hữu ích: <a class="header-anchor" href="#lien-ket-huu-ich" aria-label="Permalink to &quot;Liên kết hữu ích:&quot;">​</a></h3><p><a href="https://project-rainbowcrack.com/documentation.htm" target="_blank" rel="noreferrer">https://project-rainbowcrack.com/documentation.htm</a></p><p><a href="https://www.insecurity.be/blog/2018/01/21/retrieving-ntlm-hashes-and-what-changed-technical-writeup/" target="_blank" rel="noreferrer">https://www.insecurity.be/blog/2018/01/21/retrieving-ntlm-hashes-and-what-changed-technical-writeup/</a></p><p><a href="https://asecuritysite.com/encryption/lmhash" target="_blank" rel="noreferrer">https://asecuritysite.com/encryption/lmhash</a></p>`,31)]))}const b=a(e,[["render",s]]);export{m as __pageData,b as default};
